ModelGrow.TYPE_LV = 1           --英雄等级
ModelGrow.TYPE_EQUIP = 2        --装备评分
ModelGrow.TYPE_STAR = 3         --英雄星级
ModelGrow.TYPE_GUNE = 4         --符文天赋
ModelGrow.TYPE_GUILESKILL = 5   --公会技能
ModelGrow.TYPE_ARTIFACE = 6     --神器培养

