--注册协议监听
--预处理数据
function ModelGrow:OnModelInit()
    self:ModelNetMsgRecv(LProtoIds.StrengthResp,function(...)
        self:OnStrengthResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.StrengthOtherResp,function(...)
        self:OnStrengthOtherResp(...)
    end)
end


--在协议数据处理完之后需要调用finish
function ModelGrow:OnModelRequest()

    --self._timer = LxTimer:New()
