-------------------------------监听协议-----------------------------------
function ModelGrow:OnStrengthResp(pb)--我要变强获取自身英雄情况（主线剧情）
    self._selfInfos = {}                            --自身英雄列表
    local selfInfos = pb.selfInfo
    for i, v in ipairs(selfInfos) do
        local selfInfo = StructHeroScoreInfo:New()
        selfInfo:CreateByPb(v)
        table.insert(self._selfInfos,selfInfo)
    end
end

function ModelGrow:OnStrengthOtherResp(pb)--我要变强对比返回
    local heroId = pb.heroId
    local heroRefId = pb.heroRefId
    self._strengthInfo = StructHeroScoreInfo:New()
    self._strengthInfo:CreateByPb(pb.strengthInfo)
    if(self._strengthInfo.id ~= "")then
        return
    end
    local ref = gModelHero:GetHeroRef(heroRefId)
    local info = {}

    local refs = self:GetGrowCompareRef()
    for i, v in ipairs(refs) do
        local score = 0
        if(v.type == ModelGrow.TYPE_LV)then
            score = 1
        elseif(v.type == ModelGrow.TYPE_STAR)then
            score = ref.initStar
        end
        local data = {
            type = v.type,
            score = score,
        }
        table.insert(info,data)
    end
    self._strengthInfo = {
        id = "",
        playerName = gModelHero:GetHeroNameByRefId(heroRefId),
        playerId = 0,
        refId = heroRefId ,
        power = ref.heroWorth,
        rank = 0,
        info = info,
    }
end

-------------------------------发送协议-----------------------------------
function ModelGrow:OnStrengthReq()--我要变强获取自身英雄情况（主线剧情）
    local pb = LProtoHelper.CreateProto(LProtoIds.StrengthReq)
    SendMessage(pb,LProtoIds.StrengthReq)
end

function ModelGrow:OnStrengthOtherReq(heroId)--我要变强对比请求
    local pb = LProtoHelper.CreateProto(LProtoIds.StrengthOtherReq)
    pb.heroId = heroId          --变强英雄id
    SendMessage(pb,LProtoIds.StrengthOtherReq)
end
-------------------------------获取数据-----------------------------------
function ModelGrow:GetStrengthMe()--获取我要变强获取自身英雄情况
    return self._selfInfos or {}
end

function ModelGrow:GetStrengthOther()--获取我要变强对比
    return self._strengthInfo or nil
end

function ModelGrow:GetTypeValueSort(list)
    table.sort(list,function (a,b)
        local aSort = self:GetGrowCompareRefByRefId(a.type).sort
        local bSort = self:GetGrowCompareRefByRefId(b.type).sort
        if(aSort~=bSort)then
            return aSort<bSort
        end
        return false
    end )
    return list
end

function ModelGrow:GetTypeValue(type,list)--根据类型获取值
    for i, v in ipairs(list) do
        local ref = self:GetGrowCompareRefByRefId(v.type)
        if(ref.type==type)then
            return v.score
        end
    end
end

--# 新增第二跳转机制，【jump字段】第一跳转id；第二跳转id
--# 当type=1时，如果玩家的共鸣魔晶等级大于等于255级，则跳转时使用第二跳转
function ModelGrow:GetCompareJumpByType(type)--根据类型获取跳转id
    local ref = self:GetGrowCompareRefByRefId(type)
    if not ref then
        printInfoNR("GameTable.GrowthCompareRef; jump is not find, type = "..type)
        return nil
    end

    local jumpList = string.split(ref.jump, ';')
    if type == 1 then
        if gModelResonance:GetResonanceLv() >= 255 and jumpList[2] then
            return tonumber(jumpList[2])
        end
    end

    return tonumber(jumpList[1])
end

