function ModelGrow:GetGrowConfigRef()--获取tab列表
    local list={}
    for i, v in pairs(GameTable.GrowthConfigRef) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        if(a.sort~=b.sort)then
            return a.sort<b.sort
        end
        return false
    end)
    return list
end

function ModelGrow:GetGrowCompareRef()
