function ModelGrow:GetGrowItemJumpRef(index)--获取资源获取途径列表
    local list = {}
    local ref = self:GetGrowItemRef()[index]
    for i, v in pairs(GameTable.GrowthItemJumpRef) do
        if(v.type==ref.type)then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.sort < b.sort
    end)
    return list
end

