----红点逻辑
function ModelGrow:CheckRecommendRed()
    for i, v in ipairs(GameTable.GrowthLineupRef) do
        local finishCond = v.finishCond
        local taskData = gModelQuest:GetTaskDataByRefId(finishCond)
        if taskData then
            local state= taskData:GetState()
            if state == 1 then
                return true
            end
        end
    end

    return false
end


